import matplotlib.pyplot as pltprize_pool = 350places_payed = 15first_percentage = 0.3#these will be used as a baseline for the distributions. Change laterdef distribution_1(prizes = prize_pool,players = places_payed,first = first_percentage,slope=0.5):    distribution = []    payout = first        for i in range (0, players):        place = (f"{i+1}",prizes * payout)        distribution.append(place)        payout = payout*slope            return distributiondef distribution_2(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution =[]    total = prizes        for i in range(0,players):        amount_won = total * first        distribution.append((f"{i+1}", amount_won))        total = total - amount_won        return distributiondef distribution_3(prizes = prize_pool, players = places_payed, first = first_percentage, slope = 0.05):    distribution = []    winning_percentage = first_percentage        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distributiondef distribution_4(prizes = prize_pool, players = places_payed, first = first_percentage):    distribution = []    winning_percentage = first_percentage    slope = 1/players        for i in range(0, players):        amount_won = prizes*winning_percentage        distribution.append((f"{i+1}", amount_won))        winning_percentage = winning_percentage - slope        return distribution#plotting for selectionx = list(range(0, places_payed))#Graph 1payout_1 = distribution_1()y_1 =[]for i in payout_1:    y_1.append(i[1]) plt.title("Distribution 1")plt.xlabel("Place")plt.ylabel("Payout")plt.bar(x,y_1)plt.show()#Graph 2payout_2 = distribution_2()y_2 =[]for i in payout_2:    y_2.append(i[1]) plt.title("Distribution 2")plt.xlabel("Place")plt.ylabel("Payout")plt.bar(x,y_2)plt.show()#Graph 3payout_3 = distribution_3(slope = 0.01)y_3 =[]for i in payout_3:    y_3.append(i[1]) plt.title("Distribution 3")plt.xlabel("Place")plt.ylabel("Payout")plt.bar(x,y_3)plt.show()#Graph 4payout_4 = distribution_4()y_4 =[]for i in payout_4:    y_4.append(i[1]) plt.title("Distribution 4")plt.xlabel("Place")plt.ylabel("Payout")plt.bar(x,y_4)plt.show()